#include <iostream>
#include <vector>
using namespace std;
class Solution {
public:
void enqueue(int val) {
    for (int i = front; i < n - 1; i++) 
        arr[i] = arr[i + 1];
    arr[n - 1] = val;
    n++;
}
int dequeue() {
    int res = arr[front];
    arr[front] = arr[front + 1];
    front++;
    return res;
private:
int* arr;
int front;
int n;
};
int main() {
    int n;
    cin >> n;
    Solution s(n);
    int x;
    for (int i = 0; i < n; ++i) {
        cin >> x;
        s.enqueue(x);
    }
    for (int i = 0; i < n; ++i) {
        cout << s.dequeue() << ' ';
    }
    return 0;
}
